const eng = $input.first().json;
const asset = $('Execute Workflow Trigger').first().json.asset_value || '';
if (!eng || !eng.id) {
  return [{ json: { allowed: false, reason: 'engagement_not_found', asset_value: asset } }];
}
if (eng.status !== 'active') {
  return [{ json: { allowed: false, reason: 'engagement_not_active', status: eng.status, asset_value: asset } }];
}
const now = new Date();
const start = new Date(eng.testing_window_start);
const end = new Date(eng.testing_window_end);
if (now < start || now > end) {
  return [{ json: { allowed: false, reason: 'outside_testing_window', window_start: eng.testing_window_start, window_end: eng.testing_window_end, asset_value: asset } }];
}
return [{ json: { engagement_ok: true, engagement_id: eng.id, rate_limit_profile: eng.rate_limit_profile, asset_value: asset } }];

const rules = $input.all().map(i => i.json);
const triggerData = $('Execute Workflow Trigger').first().json;
const assetValue = (triggerData.asset_value || '').toLowerCase().trim().replace(/\.$/,'');
const engId = $('Check Engagement Status').first().json.engagement_id;
const rateProfile = $('Check Engagement Status').first().json.rate_limit_profile;

function normalizeHost(h) {
  return h.toLowerCase().trim().replace(/\.$/,'').replace(/^https?:\/\//,'').split('/')[0];
}

let matched = null;
for (const rule of rules) {
  const ruleVal = normalizeHost(rule.value);
  if (rule.scope_type === 'domain' || rule.scope_type === 'web_app' || rule.scope_type === 'api') {
    if (assetValue === ruleVal) { matched = rule; break; }
  } else if (rule.scope_type === 'subdomain_wildcard') {
    const base = ruleVal.replace(/^\*\./, '');
    if (assetValue === base || assetValue.endsWith('.' + base)) { matched = rule; break; }
  } else if (rule.scope_type === 'ip') {
    if (assetValue === ruleVal) { matched = rule; break; }
  } else if (rule.scope_type === 'cidr') {
    // Basic CIDR check — for production use a proper CIDR library
    const [network, bits] = ruleVal.split('/');
    matched = null; // placeholder — analyst should verify IP scope manually
  } else if (rule.scope_type === 'environment') {
    if (assetValue.includes(ruleVal)) { matched = rule; break; }
  }
}

if (!matched) {
  return [{ json: { allowed: false, reason: 'out_of_scope', asset_value: assetValue, engagement_id: engId } }];
}

return [{ json: { allowed: true, scope_rule_id: matched.id, scope_type: matched.scope_type, asset_value: assetValue, engagement_id: engId, rate_limit_profile: rateProfile } }];
